import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { 
      console.error("Error fetching data:", err); 
    }
  };

  useEffect(() => { 
    if (isLoggedIn) fetchData(); 
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("चुकीचा पासवर्ड!");
  };

  const handleUpdate = async (id) => {
    // नवीन सर्व इनपुट फील्ड्समधून डेटा मिळवणे
    const updatedStatus = document.getElementById(`status-${id}`).value;
    const updatedProgress = document.getElementById(`progress-${id}`).value;
    const updatedPayment = document.getElementById(`pay-${id}`).value;
    const updatedBudget = document.getElementById(`budget-${id}`).value; // नवीन
    const updatedAdvance = document.getElementById(`advance-${id}`).value; // नवीन

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: updatedStatus,
        progress: updatedProgress,
        paymentStatus: updatedPayment,
        totalBudget: updatedBudget,
        advancePaid: updatedAdvance
      });
      alert("✅ प्रोजेक्ट डिटेल्स अपडेट झाले!");
      fetchData(); 
    } catch (err) {
      alert("❌ अपडेट अयशस्वी!");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("हा प्रोजेक्ट डिलीट करायचा आहे का?")) {
      try {
        await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
        fetchData();
      } catch (err) {
        alert("Delete failed!");
      }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container d-flex justify-content-center align-items-center" style={{minHeight: '80vh'}}>
        <div className="card shadow-lg p-4 border-0 text-center" style={{width: '350px'}}>
          <h3 className="fw-bold mb-4">Admin Login</h3>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Password" className="form-control mb-3 py-2 text-center" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button className="btn btn-primary w-100 fw-bold py-2 shadow">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-5 px-lg-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-primary">Freelancer Admin Panel</h2>
        <button className="btn btn-sm btn-outline-danger shadow-sm" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="table-responsive shadow rounded-4 bg-white p-2">
        <table className="table table-hover align-middle">
          <thead className="table-light text-secondary">
            <tr className="small text-uppercase">
              <th className="ps-3">Client & Service</th>
              <th>Fees (Budget / Advance)</th>
              <th>Progress & Payment</th>
              <th>Project Status</th>
              <th>Changes/Revisions</th>
              <th className="text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {requests.length > 0 ? requests.map((req) => (
              <tr key={req._id}>
                {/* १. क्लायंटची माहिती */}
                <td className="ps-3">
                  <div className="fw-bold">{req.fullName}</div>
                  <small className="text-muted">{req.serviceType}</small>
                </td>

                {/* २. फी स्ट्रक्चर (Budget & Advance) */}
                <td style={{width: '180px'}}>
                  <div className="input-group input-group-sm mb-1">
                    <span className="input-group-text">₹</span>
                    <input type="number" id={`budget-${req._id}`} className="form-control" placeholder="Total Budget" defaultValue={req.totalBudget} />
                  </div>
                  <div className="input-group input-group-sm">
                    <span className="input-group-text text-success">₹</span>
                    <input type="number" id={`advance-${req._id}`} className="form-control" placeholder="Advance Paid" defaultValue={req.advancePaid} />
                  </div>
                </td>

                {/* ३. प्रोग्रेस आणि पेमेंट स्टेटस */}
                <td>
                  <input type="number" id={`progress-${req._id}`} className="form-control form-control-sm mb-1" defaultValue={req.progress} min="0" max="100" style={{width: '70px'}} />
                  <select id={`pay-${req._id}`} className={`form-select form-select-sm fw-bold ${req.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`} defaultValue={req.paymentStatus}>
                    <option value="Unpaid">Unpaid</option>
                    <option value="Paid">Paid</option>
                  </select>
                </td>

                {/* ४. कामाची स्थिती */}
                <td>
                  <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>

                {/* ५. क्लायंटने मागितलेले बदल (Revisions) */}
                <td style={{maxWidth: '200px'}}>
                  <div className="small text-muted border p-1 rounded bg-light" style={{minHeight: '40px', overflowY: 'auto', maxHeight: '60px'}}>
                    {req.revisionsRequested || "No changes requested"}
                  </div>
                </td>

                {/* ६. ॲक्शन बटन्स */}
                <td className="text-center">
                  <div className="d-flex gap-1 justify-content-center">
                    <button className="btn btn-success btn-sm fw-bold" onClick={() => handleUpdate(req._id)}>Save</button>
                    <button className="btn btn-outline-danger btn-sm" onClick={() => handleDelete(req._id)}>
                       Delete
                    </button>
                  </div>
                </td>
              </tr>
            )) : (
                <tr><td colSpan="6" className="text-center py-5 text-muted">अद्याप कोणताही प्रोजेक्ट आलेला नाही!</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
